import java.util.Scanner;

public class XSSSecureCode {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        String sanitizedName = sanitizeInput(name);

        System.out.println("Hello, " + sanitizedName + "!");
    }

    private static String sanitizeInput(String input) {
        // Implement proper input sanitization to prevent XSS
        // For example, you can use a library like OWASP Java HTML Sanitizer:
        // https://www.owasp.org/index.php/OWASP_Java_HTML_Sanitizer_Project

        // As a simple example, you can strip out any HTML tags from the input
        return input.replaceAll("<[^>]*>", "");
    }
}

